import React, { useState } from 'react';
import { 
  User, 
  Calendar,
  FileText,
  Users
} from 'lucide-react';

const ClientForm = () => {
  const [formData, setFormData] = useState({
    clientA: '',
    clientName: '',
    hearingDate: '',
    riders: [],
    caseType: 'ECAS' // or 'Paper Case'
  });

  const [riderCount, setRiderCount] = useState(1);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleRiderChange = (index, field, value) => {
    const updatedRiders = [...formData.riders];
    if (!updatedRiders[index]) {
      updatedRiders[index] = {};
    }
    updatedRiders[index][field] = value;
    setFormData(prev => ({
      ...prev,
      riders: updatedRiders
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Form submitted:', formData);
  };

  const addRider = () => {
    setRiderCount(prev => prev + 1);
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg p-6 space-y-6">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-6">Client Information Form</h2>
        
        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Client A# */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700 dark:text-gray-200">Client A#</label>
            <div className="relative">
              <FileText className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
              <input
                type="text"
                name="clientA"
                value={formData.clientA}
                onChange={handleInputChange}
                className="pl-10 w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm"
                placeholder="Enter Client A#"
              />
            </div>
          </div>

          {/* Client Name */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700 dark:text-gray-200">Client Name</label>
            <div className="relative">
              <User className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
              <input
                type="text"
                name="clientName"
                value={formData.clientName}
                onChange={handleInputChange}
                className="pl-10 w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm"
                placeholder="Enter Client Name"
              />
            </div>
          </div>

          {/* Hearing Date */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700 dark:text-gray-200">Hearing Date</label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
              <input
                type="date"
                name="hearingDate"
                value={formData.hearingDate}
                onChange={handleInputChange}
                className="pl-10 w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm"
              />
            </div>
          </div>

          {/* Case Type */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700 dark:text-gray-200">Case Type</label>
            <select
              name="caseType"
              value={formData.caseType}
              onChange={handleInputChange}
              className="w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm"
            >
              <option value="ECAS">ECAS</option>
              <option value="Paper Case">Paper Case</option>
            </select>
          </div>

          {/* Riders Section */}
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <label className="text-sm font-medium text-gray-700 dark:text-gray-200">Riders</label>
              <button
                type="button"
                onClick={addRider}
                className="px-4 py-2 text-sm bg-blue-500 text-white rounded-lg hover:bg-blue-600"
              >
                Add Rider
              </button>
            </div>

            {[...Array(riderCount)].map((_, index) => (
              <div key={index} className="space-y-4 p-4 border border-gray-200 dark:border-gray-700 rounded-lg">
                <div className="relative">
                  <Users className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                  <input
                    type="text"
                    value={formData.riders[index]?.name || ''}
                    onChange={(e) => handleRiderChange(index, 'name', e.target.value)}
                    className="pl-10 w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm"
                    placeholder="Rider Name"
                  />
                </div>

                <div className="flex space-x-4">
                  <div className="flex items-center">
                    <input
                      type="radio"
                      name={`age-${index}`}
                      value="minor"
                      checked={formData.riders[index]?.ageStatus === 'minor'}
                      onChange={(e) => handleRiderChange(index, 'ageStatus', 'minor')}
                      className="mr-2"
                    />
                    <label>Minor</label>
                  </div>
                  <div className="flex items-center">
                    <input
                      type="radio"
                      name={`age-${index}`}
                      value="adult"
                      checked={formData.riders[index]?.ageStatus === 'adult'}
                      onChange={(e) => handleRiderChange(index, 'ageStatus', 'adult')}
                      className="mr-2"
                    />
                    <label>Adult</label>
                  </div>
                </div>

                <div className="relative">
                  <FileText className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                  <input
                    type="text"
                    value={formData.riders[index]?.aNumber || ''}
                    onChange={(e) => handleRiderChange(index, 'aNumber', e.target.value)}
                    className="pl-10 w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm"
                    placeholder="A#"
                  />
                </div>
              </div>
            ))}
          </div>

          {/* Submit Button */}
          <button
            type="submit"
            className="w-full bg-blue-500 text-white py-3 px-4 rounded-lg hover:bg-blue-600 transition-colors"
          >
            Submit Form
          </button>
        </form>
      </div>
    </div>
  );
};

export default ClientForm;
